void dfs(vector<vector<int>>& image, int r, int c, int startColor, int color, vector<vector<bool>>& visited)
{
    int rows = image.size(), cols = image[0].size();
    if (r < 0 || r >= rows || c < 0 || c >= cols) return;
    if (visited[r][c] || image[r][c] != startColor) return;

    visited[r][c] = true;
    image[r][c] = color;
    dfs(image, r + 1, c, startColor, color, visited);
    dfs(image, r - 1, c, startColor, color, visited);
    dfs(image, r, c + 1, startColor, color, visited);
    dfs(image, r, c - 1, startColor, color, visited);
}

