#include <iostream>
#include <vector>

using namespace std;

bool touchesBorder(vector<vector<char>>& board, int r, int c, vector<vector<bool>>& visited)
{
    int rows = board.size(), cols = board[0].size();
    if (r < 0 || r >= rows || c < 0 || c >= cols) return false;
    if (visited[r][c] || board[r][c] != 'O') return false;

    visited[r][c] = true;
    if (r == 0 || r == rows - 1 || c == 0 || c == cols - 1) return true;

    bool result = false;
    result |= touchesBorder(board, r + 1, c, visited);
    result |= touchesBorder(board, r - 1, c, visited);
    result |= touchesBorder(board, r, c + 1, visited);
    result |= touchesBorder(board, r, c - 1, visited);
    return result;
}

void solve(vector<vector<char>>& board)
{
    int rows = board.size(), cols = board[0].size();
    for (int r = 0; r < rows; r++)
        for (int c = 0; c < cols; c++)
            if (board[r][c] == 'O')
            {
                vector<vector<bool>> visited(rows, vector<bool>(cols, false));
                if (!touchesBorder(board, r, c, visited))
                    board[r][c] = 'X';
            }
}

int main()
{
    vector<vector<char>> board = {
        {'X', 'X', 'X', 'X'},
        {'X', 'O', 'O', 'X'},
        {'X', 'X', 'O', 'X'},
        {'X', 'O', 'X', 'X'}
    };

    solve(board);
    for (auto &row : board)
    {
        for (char ch : row) cout << ch << " ";
        cout << "| ";
    }

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

void markSafe(vector<vector<char>>& board, int r, int c)
{
    int rows = board.size(), cols = board[0].size();
    if (r < 0 || r >= rows || c < 0 || c >= cols) return;
    if (board[r][c] != 'O') return;

    board[r][c] = '#'; // temporarily mark as safe
    markSafe(board, r + 1, c);
    markSafe(board, r - 1, c);
    markSafe(board, r, c + 1);
    markSafe(board, r, c - 1);
}

void solve(vector<vector<char>>& board)
{
    int rows = board.size(), cols = board[0].size();

    for (int r = 0; r < rows; r++)
    {
        markSafe(board, r, 0);
        markSafe(board, r, cols - 1);
    }
    for (int c = 0; c < cols; c++)
    {
        markSafe(board, 0, c);
        markSafe(board, rows - 1, c);
    }

    for (int r = 0; r < rows; r++)
        for (int c = 0; c < cols; c++)
        {
            if (board[r][c] == 'O') board[r][c] = 'X';
            else if (board[r][c] == '#') board[r][c] = 'O';
        }
}

int main()
{
    vector<vector<char>> board = {
        {'X', 'X', 'X', 'X'},
        {'X', 'O', 'O', 'X'},
        {'X', 'X', 'O', 'X'},
        {'X', 'O', 'X', 'X'}
    };

    solve(board);
    for (auto &row : board)
    {
        for (char ch : row) cout << ch << " ";
        cout << "| ";
    }

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

bool canReach(vector<vector<int>>& heights, int r, int c, bool isPacific, vector<vector<bool>>& visited)
{
    int rows = heights.size(), cols = heights[0].size();
    if (visited[r][c]) return false;
    visited[r][c] = true;

    bool reached = isPacific ? (r == 0 || c == 0) : (r == rows - 1 || c == cols - 1);
    if (reached) return true;

    int dr[] = {1, -1, 0, 0};
    int dc[] = {0, 0, 1, -1};
    for (int i = 0; i < 4; i++)
    {
        int nr = r + dr[i], nc = c + dc[i];
        if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && heights[nr][nc] <= heights[r][c])
            if (canReach(heights, nr, nc, isPacific, visited)) return true;
    }
    return false;
}

vector<vector<int>> pacificAtlantic(vector<vector<int>>& heights)
{
    int rows = heights.size(), cols = heights[0].size();
    vector<vector<int>> result;

    for (int r = 0; r < rows; r++)
        for (int c = 0; c < cols; c++)
        {
            vector<vector<bool>> visitedP(rows, vector<bool>(cols, false));
            vector<vector<bool>> visitedA(rows, vector<bool>(cols, false));
            if (canReach(heights, r, c, true, visitedP) && canReach(heights, r, c, false, visitedA))
                result.push_back({r, c});
        }
    return result;
}

int main()
{
    vector<vector<int>> heights = {
        {1, 2, 2, 3, 5},
        {3, 2, 3, 4, 4},
        {2, 4, 5, 3, 1},
        {6, 7, 1, 4, 5},
        {5, 1, 1, 2, 4}
    };

    vector<vector<int>> result = pacificAtlantic(heights);
    for (auto &cell : result) cout << "[" << cell[0] << "," << cell[1] << "] ";

    return 0;
}

